	local impbutton = CreateFrame("Button", nil, EditModeManagerFrame, "UIPanelButtonTemplate")
	impbutton:SetText("使用简繁的编辑模式")
	impbutton:SetWidth(177)
	impbutton:SetPoint("LEFT",EditModeManagerFrame.LayoutDropdown,"RIGHT", 20, 0)
	impbutton:SetScript("OnClick", function()
		local mylayout = C_EditMode.ConvertStringToLayoutInfo(layoutString)
		if mylayout then
			mylayout.layoutName = "简繁的编辑模式"
			mylayout.layoutType = 1
			
			-- 1. 获取一次数据并存入变量，确保操作的是同一个 Table
			local allLayouts = C_EditMode.GetLayouts()
			local layoutsList = allLayouts.layouts
			
			-- 2. 职业数量限制v.layoutType == 2，通用数量限制v.layoutType == 1,上限是Constants.EditModeConsts.EditModeMaxLayoutsPerType
			local account = 0
			for k,v in ipairs(layoutsList) do
				if v.layoutType == 1 then
					account = account + 1
				end
			end
			if account >= Constants.EditModeConsts.EditModeMaxLayoutsPerType then
				print("|cffFF0000通用布局数量已达上限,需要先删除一个|r")
			else
				-- 3. 插入数据
				table.insert(layoutsList, mylayout)
				
				-- 4. 保存刚才修改过的那个变量
				C_EditMode.SaveLayouts(allLayouts)
				
				-- 5. 激活最新添加的布局（通常是最后一个）
				C_EditMode.SetActiveLayout(#layoutsList+1)
				
				print("|cff00FFFF简繁|r|cff00FF00的布局已成功保存并启用|r")
			end
		else
			print("|cffFF0000错误: 字符串格式非法, 无法转换|r")
		end
	end)


